module johnson_counter_8bit(
    input clk,
    input rst,
    output [7:0] count
);

    reg [7:0] obf_shift_reg;

    always @(posedge clk) begin
        if (rst) begin
            obf_shift_reg <= 8'b11111111;
        end else begin
            obf_shift_reg <= {obf_shift_reg[6:0], ~obf_shift_reg[7]};
        end
    end

    assign count = obf_shift_reg;

endmodule
